import React, { useEffect, useState, useRef } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

export default function ReelsPage() {
  const { user } = useAuth();
  const [reels, setReels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [likedReels, setLikedReels] = useState(new Set());
  const containerRef = useRef(null);
  const scrollTimeoutRef = useRef(null);

  useEffect(() => {
    api
      .get('/movie-reels')
      .then((res) => {
        // Transform reels to include YouTube video URLs
        const transformedReels = (res.data || []).map((reel) => ({
          ...reel,
          videoUrl: reel.clipUrl || `https://www.youtube.com/embed/${generateRandomYouTubeVideoId()}?autoplay=1&mute=1&controls=1`
        }));
        setReels(transformedReels);
      })
      .catch((err) => {
        console.error('Failed to fetch reels:', err);
        setReels([]);
      })
      .finally(() => setLoading(false));
  }, []);

  // Generate random YouTube video IDs for demo (in production, use actual video URLs)
  const generateRandomYouTubeVideoId = () => {
    const ids = ['dQw4w9WgXcQ', '9bZkp7q19f0', 'jNQXAC9IVRw', 'oHg5SJYRHA0', '_9mwEUMtpWI'];
    return ids[Math.floor(Math.random() * ids.length)];
  };

  // Handle scroll/swipe navigation
  useEffect(() => {
    const handleWheel = (e) => {
      if (scrollTimeoutRef.current) return;

      if (e.deltaY > 0) {
        setCurrentIndex((prev) => Math.min(prev + 1, reels.length - 1));
      } else if (e.deltaY < 0) {
        setCurrentIndex((prev) => Math.max(prev - 1, 0));
      }

      scrollTimeoutRef.current = setTimeout(() => {
        scrollTimeoutRef.current = null;
      }, 800);
    };

    // Touch swipe handling
    let touchStart = 0;
    const handleTouchStart = (e) => {
      touchStart = e.touches[0].clientY;
    };

    const handleTouchEnd = (e) => {
      const touchEnd = e.changedTouches[0].clientY;
      const diff = touchStart - touchEnd;

      if (Math.abs(diff) > 50) {
        if (diff > 0) {
          setCurrentIndex((prev) => Math.min(prev + 1, reels.length - 1));
        } else {
          setCurrentIndex((prev) => Math.max(prev - 1, 0));
        }
      }
    };

    const container = containerRef.current;
    if (container) {
      container.addEventListener('wheel', handleWheel, { passive: true });
      container.addEventListener('touchstart', handleTouchStart, { passive: true });
      container.addEventListener('touchend', handleTouchEnd, { passive: true });
    }

    return () => {
      if (container) {
        container.removeEventListener('wheel', handleWheel);
        container.removeEventListener('touchstart', handleTouchStart);
        container.removeEventListener('touchend', handleTouchEnd);
      }
    };
  }, [reels.length]);

  const handleLike = (id) => {
    setLikedReels((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(id)) {
        newSet.delete(id);
      } else {
        newSet.add(id);
      }
      return newSet;
    });
  };

  const handleShare = (reel) => {
    const text = `Check out this movie edit: ${reel.title}`;
    if (navigator.share) {
      navigator.share({ title: 'Movie Edit', text });
    } else {
      alert(`Share: ${text}`);
    }
  };

  if (loading) {
    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#000' }}>
        <div style={{ textAlign: 'center' }}>
          <div className="spinner" />
          <p style={{ marginTop: '16px', color: 'var(--text-dim)' }}>Loading reels...</p>
        </div>
      </div>
    );
  }

  if (reels.length === 0) {
    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#000' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '16px' }}>🎬</div>
          <h2 style={{ fontSize: '1.5rem', marginBottom: '8px' }}>No Edits Available</h2>
          <p style={{ color: 'var(--text-dim)' }}>Check back soon!</p>
        </div>
      </div>
    );
  }

  const currentReel = reels[currentIndex];
  const scrollProgress = (currentIndex / (reels.length - 1)) * 100;

  return (
    <div
      ref={containerRef}
      style={{
        width: '100%',
        height: '100vh',
        background: '#000',
        overflow: 'hidden',
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Background blur */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: `url(${currentReel.poster})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'blur(20px) brightness(0.2)',
          zIndex: 0
        }}
      />

      {/* Content container */}
      <div style={{ position: 'relative', zIndex: 1, width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {/* Video player */}
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 24px' }}>
          <iframe
            width="100%"
            height="100%"
            style={{
              maxWidth: '500px',
              maxHeight: '85vh',
              borderRadius: '12px',
              border: 'none',
              boxShadow: '0 20px 60px rgba(0,0,0,0.8)'
            }}
            src={currentReel.videoUrl}
            title={currentReel.title}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        </div>

        {/* Scrollbar on right */}
        <div
          style={{
            position: 'absolute',
            right: '100px',
            top: '50%',
            transform: 'translateY(-50%)',
            width: '4px',
            height: '200px',
            background: 'rgba(255,255,255,0.1)',
            borderRadius: '2px',
            overflow: 'hidden'
          }}
        >
          <div
            style={{
              width: '100%',
              height: '100%',
              background: 'linear-gradient(180deg, var(--red), rgba(229,9,20,0.5))',
              borderRadius: '2px',
              transform: `translateY(-${100 - scrollProgress}%)`,
              transition: 'transform 0.3s ease',
              boxShadow: '0 0 8px rgba(229,9,20,0.6)'
            }}
          />
        </div>

        {/* Right side controls */}
        <div style={{ position: 'absolute', right: '20px', bottom: '120px', display: 'flex', flexDirection: 'column', gap: '24px', zIndex: 10 }}>
          {/* Like button */}
          <button
            onClick={() => handleLike(currentReel.id)}
            style={{
              width: '50px',
              height: '50px',
              borderRadius: '50%',
              background: likedReels.has(currentReel.id) ? 'var(--red)' : 'rgba(255,255,255,0.2)',
              border: 'none',
              color: '#fff',
              fontSize: '1.5rem',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              backdropFilter: 'blur(4px)'
            }}
            onMouseEnter={(e) => {
              if (!likedReels.has(currentReel.id)) {
                e.currentTarget.style.background = 'rgba(255,255,255,0.3)';
              }
            }}
            onMouseLeave={(e) => {
              if (!likedReels.has(currentReel.id)) {
                e.currentTarget.style.background = 'rgba(255,255,255,0.2)';
              }
            }}
            title="Like"
          >
            {likedReels.has(currentReel.id) ? '❤️' : '🤍'}
          </button>

          {/* Comment button */}
          <button
            style={{
              width: '50px',
              height: '50px',
              borderRadius: '50%',
              background: 'rgba(255,255,255,0.2)',
              border: 'none',
              color: '#fff',
              fontSize: '1.5rem',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              backdropFilter: 'blur(4px)'
            }}
            onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.3)')}
            onMouseLeave={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.2)')}
            onClick={() => alert(`Comments for ${currentReel.title} coming soon!`)}
            title="Comment"
          >
            💬
          </button>

          {/* Share button */}
          <button
            onClick={() => handleShare(currentReel)}
            style={{
              width: '50px',
              height: '50px',
              borderRadius: '50%',
              background: 'rgba(255,255,255,0.2)',
              border: 'none',
              color: '#fff',
              fontSize: '1.5rem',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              backdropFilter: 'blur(4px)'
            }}
            onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.3)')}
            onMouseLeave={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.2)')}
            title="Share"
          >
            📤
          </button>

          {/* More options */}
          <button
            style={{
              width: '50px',
              height: '50px',
              borderRadius: '50%',
              background: 'rgba(255,255,255,0.2)',
              border: 'none',
              color: '#fff',
              fontSize: '1.5rem',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              backdropFilter: 'blur(4px)'
            }}
            onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.3)')}
            onMouseLeave={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.2)')}
            onClick={() => alert('More options coming soon!')}
            title="More"
          >
            ⋯
          </button>
        </div>

        {/* Bottom info */}
        <div
          style={{
            position: 'absolute',
            bottom: '20px',
            left: '20px',
            right: '100px',
            background: 'linear-gradient(180deg, transparent 0%, rgba(0,0,0,0.9) 100%)',
            padding: '40px 20px 20px',
            borderRadius: '8px',
            color: '#fff'
          }}
        >
          <h2 style={{ margin: '0 0 8px 0', fontSize: '1.3rem', fontWeight: '700' }}>{currentReel.title}</h2>
          <p style={{ margin: '0 0 12px 0', color: 'rgba(255,255,255,0.8)', fontSize: '0.9rem' }}>
            {currentReel.year} • {currentReel.genre}
          </p>
          {currentReel.rating && (
            <p style={{ margin: '0 0 8px 0', color: 'var(--red)', fontSize: '0.85rem', fontWeight: '600' }}>
              ⭐ {currentReel.rating} Rating
            </p>
          )}
        </div>

        {/* Navigation indicator */}
        <div
          style={{
            position: 'absolute',
            top: '20px',
            left: '50%',
            transform: 'translateX(-50%)',
            color: '#fff',
            fontSize: '0.9rem',
            background: 'rgba(0,0,0,0.6)',
            padding: '8px 16px',
            borderRadius: '20px',
            backdropFilter: 'blur(4px)',
            border: '1px solid rgba(255,255,255,0.2)'
          }}
        >
          {currentIndex + 1} / {reels.length}
        </div>

        {/* Keyboard hint */}
        <div
          style={{
            position: 'absolute',
            bottom: '20px',
            right: '20px',
            fontSize: '0.75rem',
            color: 'rgba(255,255,255,0.5)',
            textAlign: 'right'
          }}
        >
          Scroll or Swipe ↑↓
        </div>
      </div>
    </div>
  );
}
